class KStacks:
    def __init__(self, num_stacks, capacity):
        self.num_stacks = num_stacks
        self.capacity = capacity

        self.arr = [0] * capacity 
        self.top = [-1] * num_stacks 
        self.next = [0] * capacity 
        self.free = 0 

        for i in range(capacity - 1):
            self.next[i] = i + 1
        self.next[capacity - 1] = -1

    def is_empty(self, sn):
        return self.top[sn] == -1

    def is_full(self):
        return self.free == -1

    def push(self, item, sn):
        if self.is_full():
            raise Exception("Stack overflow")

        if not (0 <= sn < self.num_stacks):
            raise ValueError(f"Invalid stack number {sn}. Must be between 0 and {self.num_stacks - 1}.")

        i = self.free
        self.free = self.next[i]

        self.arr[i] = item

        self.next[i] = self.top[sn]
        self.top[sn] = i

    def pop(self, sn):
        if self.is_empty(sn):
            raise Exception("Stack underflow")

        if not (0 <= sn < self.num_stacks):
            raise ValueError(f"Invalid stack number {sn}. Must be between 0 and {self.num_stacks - 1}.")

        i = self.top[sn]

        self.top[sn] = self.next[i]

        self.next[i] = self.free
        self.free = i

        return self.arr[i]

    def peek(self, sn):
        if self.is_empty(sn):
            raise Exception("Stack is empty")
        if not (0 <= sn < self.num_stacks):
            raise ValueError(f"Invalid stack number {sn}. Must be between 0 and {self.num_stacks - 1}.")
        return self.arr[self.top[sn]]
